<?php
namespace App\Http\Requests\Admin\Content;
use App\Domain\Characters\Templates\CharacterTemplatePresentationGender;use App\Domain\WorldCatalog\CatalogStatus;use Illuminate\Foundation\Http\FormRequest;use Illuminate\Validation\Rule;
final class CharacterTemplateRequest extends FormRequest{protected function prepareForValidation(){foreach(['code','body_type']as$f)if(is_string($this->input($f)))$this->merge([$f=>strtolower(trim($this->input($f)))]);}public function authorize(){return true;}public function rules(){$template=$this->route('character_template');return['code'=>['required','string','min:2','max:64','regex:/^[a-z0-9_-]+$/',Rule::unique('character_templates','code')->ignore($template?$template->id:null)],'name'=>'required|string|max:255','description'=>'nullable|string','character_class_id'=>'required|integer|exists:character_classes,id','presentation_gender'=>['required',Rule::in(CharacterTemplatePresentationGender::all())],'body_type'=>['required','string','min:2','max:64','regex:/^[a-z0-9_-]+$/'],'status'=>['required',Rule::in(CatalogStatus::values())],'sort_order'=>'required|integer|min:0','base_max_health'=>'required|integer|min:1','base_attack'=>'required|integer|min:0','base_defense'=>'required|integer|min:0','base_accuracy'=>'required|integer|min:0','base_evasion'=>'required|integer|min:0','base_critical_rate'=>'required|numeric|min:0|max:100','image'=>'nullable|file|max:5120|mimetypes:image/png,image/jpeg,image/webp'];}public function messages(){return['code.regex'=>'El código debe usar minúsculas, números, guion o guion bajo.','body_type.regex'=>'El tipo corporal debe usar minúsculas, números, guion o guion bajo.','image.mimetypes'=>'Solo se permiten imágenes PNG, WebP o JPEG.'];}}
